drop table #t2
drop table #t3



select distinct t.part_id, isnull(QTY_ON_HAND,0) as Inventory,
    --p.id as Part_ID,
    case
	   when p.id is null then 'No Part'
	   else p.id
    end  as PartNumber,
    case
	   when base_id is null then 'No Master'
	   else base_id
    end  as BaseID,
    case
	   when Reqd is null then ''
	   else Reqd
    End  as ParentPart
into #t2
from #t1 t
left outer join part p
    on p.id = t.part_id
left outer join work_order wo
    on p.id = wo.part_id
    and wo.type = 'M'
left outer join requirement r
    on wo.type = r.workorder_type
    and wo.base_id = r.workorder_base_id
    and wo.lot_id = r.workorder_lot_id
    and wo.split_id = r.workorder_split_id
    and wo.sub_id = r.workorder_sub_id
left outer join 
    (select distinct r.part_id as Part_ID, wo.base_id as Reqd 
    from requirement r
    inner join work_order wo
	   on wo.type = 'M'
	   and wo.base_id = r.workorder_base_id
	   and wo.lot_id = r.workorder_lot_id
	   and wo.split_id = r.workorder_split_id
	   and wo.sub_id = r.workorder_sub_id
    ) a
    on a.part_id = t.part_id

select t.part_id, customer_id, customer_Part_ID as [Contract], cpe.[EFFECTIVE_DATE] as EffDate, cpe.[DISCONTINUE_DATE] as DiscDate, --LastCOID,
    LastShipDate
into #t3
from 
    (select distinct part_id
    from #t2
    union
    select distinct ParentPart as part_id
    from #t2
    ) t
left outer join cust_price_effect cpe
    on cpe.part_id = t.part_id
    and (discontinue_date > getdate() or discontinue_date  is null)
left outer join 
    (select part_id, 
        --co.customer_id as LastCOID, 
	   max(shipped_date) as LastShipDate
    from shipper s
    left join cust_order_line col
	   on s.cust_order_id = col.cust_order_id
    left join customer_order co
	   on col.cust_order_id = co.id
    group by part_id --, co.customer_id 
    ) a
    on a.part_id = t.part_id
order by t.part_id


select *
from #t2 t2
inner join #t3 t3
on t2.part_id = t3.part_id
inner join #t3 t4
on t2.parentpart = t4.part_id


